const transcricao = ($json.text || '').trim();

if (!transcricao) {
  throw new Error('normaliza_audio_texto: Transcricao vazia.');
}

return [{ json: {
  tipo_entrada: 'audio',
  texto_normalizado: transcricao
} }];

const item = items[0];

if (item.json.error || !item.binary || !item.binary.data) {
  throw new Error(
    'converte_imagem_b64: Falha no download. ' +
    (item.json.error ? JSON.stringify(item.json.error) : 'Dados binarios nao encontrados.')
  );
}

const binaryBuffer = await this.helpers.getBinaryDataBuffer(item, 'data');
const base64 = binaryBuffer.toString('base64');
const mimeType = item.binary.data.mimeType || 'image/jpeg';

return [{ json: {
  data_uri: 'data:' + mimeType + ';base64,' + base64,
  mime_type: mimeType
} }];

const fileURL = $('fn_seta_dados_entrada').first().json.fileURL;

if (!fileURL) {
  throw new Error('prepara_payload_visao: fileURL nao encontrada em fn_seta_dados_entrada.');
}

const payload = {
  model: 'gpt-4o',
  messages: [
    {
      role: 'user',
      content: [
        {
          type: 'image_url',
          image_url: { url: fileURL }
        },
        {
          type: 'text',
          text: 'Voce e um assistente financeiro pessoal. Analise esta imagem. Se for recibo, comprovante ou nota fiscal: informe o estabelecimento, o valor total e a data. Se for outro documento financeiro: extraia as informacoes mais relevantes. Se nao tiver relacao com financas: descreva brevemente o conteudo. Responda em portugues em no maximo 2 frases objetivas.'
        }
      ]
    }
  ],
  max_tokens: 250
};

return [{ json: { payload: JSON.stringify(payload) } }];

try {
  const content = (($json.choices ?? [])[0]?.message?.content ?? '').trim();
  if (!content) throw new Error('Conteudo vazio na resposta do GPT-4o Vision');
  return [{ json: {
    tipo_entrada: 'imagem',
    texto_normalizado: content
  } }];
} catch (e) {
  throw new Error('normaliza_imagem_texto: ' + e.message);
}

