Formato exato:
{"categoria": "...", "subcategoria": "...", "valor": "R$ XX,XX", "data": "DD/MM/AAAA", "mensagem": "Gasto de R$ XX,XX em [subcategoria] cadastrado com sucesso!"}
DATA ATUAL: {{ $('pega_data_atual').first().json.currentDate }}
Mensagem do usuario: {{ $('formata_celular').first().json.texto_normalizado }}

parameters.jsCode:
try {
  const inputData = items[0].json.output;
  const cleanData = inputData.replace(/```json\n?/g, '').replace(/\n?```/g, '').trim();
  const parsedData = JSON.parse(cleanData);
  return [{ json: {
    categoria: parsedData.categoria || 'Outros',
    subcategoria: parsedData.subcategoria || 'Geral',
    valor: parsedData.valor || 'R$ 0,00',
    data: parsedData.data || new Date().toLocaleDateString('pt-BR'),
    mensagem: parsedData.mensagem || 'Gasto cadastrado com sucesso!'
  } }];
} catch (e) {
  throw new Error('parse_gastos: falha ao processar JSON do LLM - ' + e.message);
}

