try {
  const inputData = items[0].json.output;
  const cleanData = inputData.replace(/```json\n?/g, '').replace(/\n?```/g, '').trim();
  const parsedData = JSON.parse(cleanData);
  return [{ json: {
    categoria: parsedData.categoria || 'Outros',
    subcategoria: parsedData.subcategoria || 'Geral',
    valor: parsedData.valor || 'R$ 0,00',
    data: parsedData.data || new Date().toLocaleDateString('pt-BR'),
    mensagem: parsedData.mensagem || 'Entrada cadastrada com sucesso!'
  } }];
} catch (e) {
  throw new Error('parse_entradas: falha ao processar JSON do LLM - ' + e.message);
}

if (!items || items.length === 0 || !items[0].json.Tipo) {
  return [{ json: { mensagem: 'Nenhuma transacao registrada nos ultimos 90 dias.' } }];
}
const messages = items.map(item =>
  `[${item.json.Tipo}] ${item.json.Categoria} - ${item.json['Sub-categoria']} - ${item.json.Valor} (${item.json.Data})`
);
return [{ json: { mensagem: messages.join('\n') } }];

